class MemoryBlock:
 """Represents a block of memory (either allocated or free)"""
 def __init__(self, start_addr, size, process_id=None):
 self.start_addr = start_addr
 self.size = size
 self.process_id = process_id # None means free

 def is_free(self):
 return self.process_id is None

 def __repr__(self):
 status = f"P{self.process_id}" if self.process_id else "FREE"
 return f"[{self.start_addr:4d} - {self.start_addr + self.size - 1:4d}] {status} ({self.size}KB)"

class MemoryManager:
 """Simulates memory management with various allocation strategies"""

 def __init__(self, total_memory):
 self.total_memory = total_memory
 # Start with one large free block
 self.memory = [MemoryBlock(0, total_memory)]
 self.next_fit_index = 0 # For Next-Fit algorithm
 self.process_counter = 1

 def allocate(self, size, strategy='first-fit'):
 """Allocate memory using specified strategy"""
 if strategy == 'first-fit':
 return self._first_fit(size)
 elif strategy == 'best-fit':
 return self._best_fit(size)
 elif strategy == 'worst-fit':
 return self._worst_fit(size)
 elif strategy == 'next-fit':
 return self._next_fit(size)
 else:
 raise ValueError(f"Unknown strategy: {strategy}")

 def _first_fit(self, size):
 """Find first hole big enough"""
 for i, block in enumerate(self.memory):
 if block.is_free() and block.size >= size:
 return self._allocate_block(i, size)
 return None

 def _best_fit(self, size):
 """Find smallest hole big enough (minimizes wasted space)"""
 best_idx = -1
 best_size = float('inf')

 for i, block in enumerate(self.memory):
 if block.is_free() and block.size >= size:
 if block.size < best_size:
 best_size = block.size
 best_idx = i

 if best_idx >= 0:
 return self._allocate_block(best_idx, size)
 return None

 def _worst_fit(self, size):
 """Find largest hole available"""
 worst_idx = -1
 worst_size = -1

 for i, block in enumerate(self.memory):
 if block.is_free() and block.size >= size:
 if block.size > worst_size:
 worst_size = block.size
 worst_idx = i

 if worst_idx >= 0:
 return self._allocate_block(worst_idx, size)
 return None

 def _next_fit(self, size):
 """Start searching from last allocation point"""
 n = len(self.memory)
 for i in range(n):
 idx = (self.next_fit_index + i) % n
 block = self.memory[idx]
 if block.is_free() and block.size >= size:
 result = self._allocate_block(idx, size)
 self.next_fit_index = idx
 return result
 return None

 def _allocate_block(self, idx, size):
 """Helper to allocate a block and create remainder if needed"""
 block = self.memory[idx]
 allocated_addr = block.start_addr

 if block.size > size:
 # Split: create new free block for remainder
 remainder = MemoryBlock(
 block.start_addr + size,
 block.size - size
 )
 self.memory[idx] = MemoryBlock(allocated_addr, size, self.process_counter)
 self.memory.insert(idx + 1, remainder)
 else:
 block.process_id = self.process_counter

 pid = self.process_counter
 self.process_counter += 1
 return {
 'process_id': pid,
 'address': allocated_addr,
 'size': size
 }

 def deallocate(self, process_id):
 """Free memory allocated to a process"""
 for i, block in enumerate(self.memory):
 if block.process_id == process_id:
 block.process_id = None
 self._merge_adjacent_free_blocks()
 return True
 return False

 def _merge_adjacent_free_blocks(self):
 """Combine adjacent free blocks to reduce fragmentation"""
 if not self.memory:
 return

 merged = [self.memory[0]]
 for block in self.memory[1:]:
 if merged[-1].is_free() and block.is_free():
 merged[-1].size += block.size
 else:
 merged.append(block)
 self.memory = merged

 def get_statistics(self):
 """Calculate memory fragmentation statistics"""
 free_blocks = [b for b in self.memory if b.is_free()]
 allocated_blocks = [b for b in self.memory if not b.is_free()]

 total_free = sum(b.size for b in free_blocks)
 total_allocated = sum(b.size for b in allocated_blocks)

 # Internal fragmentation: wasted space within allocated blocks
 internal_frag = sum(b.size for b in allocated_blocks)

 # External fragmentation: number of free holes
 external_frag = len(free_blocks)

 return {
 'total_memory': self.total_memory,
 'used': total_allocated,
 'free': total_free,
 'utilization': (total_allocated / self.total_memory) * 100,
 'free_blocks': len(free_blocks),
 'external_fragmentation': external_frag,
 'internal_fragmentation': 0 # No internal in this simple model
 }

 def display(self):
 """Display current memory state"""
 print("\n" + "="*60)
 print(f"Memory Map (Total: {self.total_memory}KB)")
 print("="*60)
 for block in self.memory:
 print(block)
 print("="*60)

# Demonstration
if __name__ == "__main__":
 # Create memory manager with 1000KB
 mm = MemoryManager(1000)

 print("Initial memory:")
 mm.display()

 # Allocate processes using First-Fit
 allocations = [
 ("P1", 200, 'first-fit'),
 ("P2", 150, 'first-fit'),
 ("P3", 300, 'first-fit'),
 ]

 print("\n--- Allocating Processes ---")
 for name, size, strategy in allocations:
 result = mm.allocate(size, strategy)
 if result:
 print(f"{name} ({size}KB): Allocated at address {result['address']}")
 else:
 print(f"{name} ({size}KB): Allocation failed!")

 mm.display()
 stats = mm.get_statistics()
 print(f"\nStatistics: Used={stats['used']}KB, Free={stats['free']}KB, "
 f"Utilization={stats['utilization']:.1f}%")

 # Deallocate P2 to demonstrate external fragmentation
 print("\n--- Deallocating P2 ---")
 mm.deallocate(2)
 mm.display()

 # Try to allocate a larger process
 print("\n--- Trying to allocate P4 (250KB) ---")
 result = mm.allocate(250, 'first-fit')
 if result:
 print(f"P4 allocated at address {result['address']}")
 else:
 print("P4 allocation failed - External fragmentation!")

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Memory Protection: Base and Limit Registers
// This simulates how OS protects processes from accessing unauthorized memory

typedef struct {
 unsigned int base; // Smallest legal physical address
 unsigned int limit; // Size of the memory region
 int process_id; // Which process owns this memory
} MemoryRegion;

typedef struct {
 MemoryRegion region; // Current process's memory region
 unsigned int logical_addr; // Last accessed logical address
 unsigned int physical_addr; // Translated physical address
 bool last_access_valid; // Whether last access was valid
} ProcessContext;

// Global memory array (simulated RAM)
#define MEMORY_SIZE 65536
unsigned char memory[MEMORY_SIZE];

// Initialize a process's memory region
void load_process(ProcessContext *ctx, int pid, unsigned int base, unsigned int limit) {
 ctx->region.base = base;
 ctx->region.limit = limit;
 ctx->region.process_id = pid;
 ctx->logical_addr = 0;
 ctx->physical_addr = 0;
 ctx->last_access_valid = false;
 printf("Process %d loaded: Base=0x%04X, Limit=%u bytes\n", 
 pid, base, limit);
}

// Translate logical address to physical address with bounds checking
// Returns true if access is valid, false if it's a protection violation
bool translate_address(ProcessContext *ctx, unsigned int logical_addr) {
 ctx->logical_addr = logical_addr;

 // Check if address exceeds limit (bounds check)
 if (logical_addr >= ctx->region.limit) {
 ctx->last_access_valid = false;
 printf("PROTECTION VIOLATION: Logical address 0x%04X ", logical_addr);
 printf("exceeds limit %u for process %d\n", 
 ctx->region.limit, ctx->region.process_id);
 return false;
 }

 // Translate: physical = base + logical
 ctx->physical_addr = ctx->region.base + logical_addr;
 ctx->last_access_valid = true;

 return true;
}

// Read a byte from memory (with protection)
bool read_memory(ProcessContext *ctx, unsigned int logical_addr, unsigned char *value) {
 if (!translate_address(ctx, logical_addr)) {
 return false; // Protection fault
 }

 *value = memory[ctx->physical_addr];
 printf("READ: Process %d -> Logical[0x%04X] = Physical[0x%04X] = 0x%02X\n",
 ctx->region.process_id, logical_addr, ctx->physical_addr, *value);
 return true;
}

// Write a byte to memory (with protection)
bool write_memory(ProcessContext *ctx, unsigned int logical_addr, unsigned char value) {
 if (!translate_address(ctx, logical_addr)) {
 return false; // Protection fault
 }

 memory[ctx->physical_addr] = value;
 printf("WRITE: Process %d -> Logical[0x%04X] = Physical[0x%04X] = 0x%02X\n",
 ctx->region.process_id, logical_addr, ctx->physical_addr, value);
 return true;
}

// Simulate context switch between processes
void context_switch(ProcessContext *ctx, int new_pid, unsigned int new_base, unsigned int new_limit) {
 printf("\n--- Context Switch: Loading Process %d ---\n", new_pid);
 load_process(ctx, new_pid, new_base, new_limit);
}

// Demonstrate memory protection
int main() {
 ProcessContext current_process;
 unsigned char data;

 printf("=== Memory Protection Demo: Base and Limit Registers ===\n\n");

 // Initialize some memory
 for (int i = 0; i < 100; i++) {
 memory[i] = i;
 }

 // Load Process 1: starts at physical address 0x1000, size 1024 bytes
 load_process(&current_process, 1, 0x1000, 1024);

 // Valid accesses
 printf("\n--- Valid Memory Accesses ---\n");
 write_memory(&current_process, 0x0000, 0xAB); // Logical 0 -> Physical 0x1000
 write_memory(&current_process, 0x0100, 0xCD); // Logical 256 -> Physical 0x1100
 write_memory(&current_process, 0x03FF, 0xEF); // Logical 1023 -> Physical 0x13FF

 read_memory(&current_process, 0x0000, &data);
 read_memory(&current_process, 0x0100, &data);

 // Invalid access: beyond limit
 printf("\n--- Invalid Memory Access (Beyond Limit) ---\n");
 write_memory(&current_process, 0x0500, 0x12); // Logical 1280 > Limit 1024

 // Context switch to Process 2: different memory region
 context_switch(&current_process, 2, 0x2000, 512);

 printf("\n--- Process 2 Accesses ---\n");
 write_memory(&current_process, 0x0000, 0x55); // Logical 0 -> Physical 0x2000
 read_memory(&current_process, 0x01FF, &data); // Logical 511 -> Physical 0x21FF

 // Try to access Process 1's memory (should work due to MMU simulation)
 printf("\n--- Attempting to access Process 1's memory from Process 2 ---\n");
 write_memory(&current_process, 0x1000, 0x99); // Logical 4096 -> Physical 0x3000 (safe)

 // This demonstrates that each process has its own address space
 printf("\n=== Demo Complete ===\n");

 return 0;
}
